function csvEscape(value) {
    const str = (value === undefined || value === null) ? "" : String(value);
    return '"' + str.replace(/"/g, '""') + '"';
}

function extractScore(vuln) {
    const cvss = vuln.CVSS || {};
    for (const source of Object.keys(cvss)) {
        const entry = cvss[source] || {};
        if (typeof entry.V3Score === "number") return entry.V3Score;
        if (typeof entry.V2Score === "number") return entry.V2Score;
    }
    return "";
}

if (!$RunScan.success || $RunScan.exitcode !== 0) {
    throw new Error(
        "RunScan (the trivy_scan.sh invocation) failed (exitcode=" + $RunScan.exitcode + ", error=" +
        $RunScan.error + ") - check that the script was uploaded/marked executable correctly by " +
        "UploadScanScript, and that the timeout on RunScan is long enough for a full scan."
    );
}
if (!$FetchScanResult.result || !$FetchScanResult.result.trim()) {
    throw new Error(
        "FetchScanResult (SFTP Get File on /tmp/trivy-scan.json) returned no content, even though " +
        "RunScan itself reported success - the scan may have written its output file somewhere unexpected."
    );
}
const report = JSON.parse($FetchScanResult.result);
const rows = [];
const header = ["CVE", "Host IPAddress", "Package", "Package Version", "Package Path", "severity", "Score", "hasFix", "Fixed Version", "Description", "Host Name"];
rows.push(header.map(csvEscape).join(","));

for (const result of (report.Results || [])) {
    if (result.Class !== "os-pkgs") continue;
    for (const vuln of (result.Vulnerabilities || [])) {
        rows.push([
            vuln.VulnerabilityID,
            $target_host,
            vuln.PkgName,
            vuln.InstalledVersion,
            "",
            (vuln.Severity || "").toLowerCase(),
            extractScore(vuln),
            vuln.FixedVersion ? "Y" : "N",
            vuln.FixedVersion || "",
            vuln.Description,
            $target_host
        ].map(csvEscape).join(","));
    }
}

$vm_scan_csv = rows.join("\n");
$metadata_str = JSON.stringify({scanner_name: "concert"});
